  ('elementary-e0adf6cd-moex-00579', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關補習及進修教育法之規定，下列敘述何者正確？', '["國民小學補習學校有入學資格之限制", "進修教育由高級中等以上學校依需要附設進修學校實施之", "國民中學補習學校相當於國民中學，修業年限不得少於二年", "國民中學畢業未繼續受教育者，得實施部分時間之職業進修教育，至十六足歲為止"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00580', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據原住民族教育法之規定，下列敘述何者錯誤？', '["本法制定係根據憲法增修條文第十條之規定而來", "高級中等以下學校於原住民學生就讀時，應對其實施民族教育", "地方政府提供原住民之語言文化教育，其費用由中央政府全額補助", "政府機關捐助基金累計超過百分之五十之財團法人，應規劃實施原住民族及多元文化教育相關課 程或活動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00581', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據校園霸凌防制準則之規定，主管機關及學校應加強實施相關教育，以作為校園霸凌之防制基礎。 下列那一項不在校園霸凌防制之明列範疇內？', '["人權教育", "生命教育", "數位學習教育", "資訊倫理教育"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00582', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據私立高級中等以上學校退場條例之規定，學校經主管機關查核認定者，列為預警學校。有關預 警學校之認定情形，下列敘述何者錯誤？', '["學校財務狀況惡化，有影響校務正常營運之虞", "私立高級中等學校合格教師比率未達百分之五十", "私立專科以上學校最近一學期維護學生受教權益檢核結果為不通過", "學校積欠教師薪資，且經學校主管機關依教師待遇條例之規定處以罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00583', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關海外臺灣學校設立及輔導辦法之規定，下列敘述何者錯誤？', '["本辦法依私立學校法規定而訂定之", "董事不得兼任校長及校內其他行政職務", "海外臺灣學校受轄區我國駐外館處之直接督導與管理", "海外臺灣學校招收具我國籍之學生，不得少於招生總人數百分之五十"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00584', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據學校型態實驗教育實施條例，有關實驗教育學校設立之相關規定，下列敘述何者錯誤？', '["招生對象為六歲至十八歲之學生", "每年級學生人數不得超過五十人", "專任教師對學生人數之比例不低於一比十五", "學生學習活動室外面積，每人不得少於三平方公尺"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00585', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據特殊教育法之規定，高級中等以下各教育階段學校得設特殊教育班。下列何者不在其辦理方式 之中？', '["巡迴輔導班", "分散式資源班", "集中式特殊教育班", "抽離式技藝學習班"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:40+00:00", "source_pdf_sha1": "307c0bcdf828", "answer_pdf_sha1": "7899b52a442e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
